SELECT MIN(population) AS smallest_population_above_average
FROM counties
WHERE population > (SELECT AVG(population) FROM counties);

SELECT c.county_name
FROM counties c
WHERE c.registered_voters > (
    SELECT AVG(s.population)
    FROM states s
);

SELECT ER.result_status, COUNT(ER.result_id)
FROM election_results ER
GROUP BY ER.result_status;
